/**
 * Grąžina pavadinimų ant titulo vertimus pagal kalbą.
 * Jei kalba neturi vertimų – grąžina anglišką versiją.
 */
export function getTitleBrandItems(lang: string | undefined): Record<string, TitleBrandItem> {
  const key = lang && SUPPORTED_LANGUAGES.includes(lang as SupportedLang) ? (lang as SupportedLang) : 'en';
  return LANG_MAP[key] ?? EN;
}
